import { test, expect } from '@playwright/test';

test('Amazon.sg search for headphones displays results', async ({ browser }) => {
  const context = await browser.newContext();
  const page = await context.newPage();

  // 1. Launch browser and navigate to Amazon.sg
  await page.goto('https://www.amazon.sg', { waitUntil: 'domcontentloaded' });

  // 2. Wait for search input (name="field-keywords")
  const searchInput = page.locator('input[name="field-keywords"]');
  await expect(searchInput).toBeVisible({ timeout: 10000 });

  // 3. Enter "headphones" and press Enter
  await searchInput.fill('headphones');
  await searchInput.press('Enter');

  // 4. Wait for search results to load
  // Amazon search results are in div[data-component-type="s-search-result"]
  const resultsLocator = page.locator('div[data-component-type="s-search-result"]');
  await expect(resultsLocator.first()).toBeVisible({ timeout: 15000 });

  // 5. Validate at least one result is displayed
  const resultsCount = await resultsLocator.count();
  expect(resultsCount).toBeGreaterThan(0);

  // 6. Close browser
  await context.close();
});
